begin;
create extension if not exists pgcrypto;
create type public.visit_visibility as enum ('private','group','link');
create type public.group_role as enum ('owner','editor','viewer');
create table public.profiles(id uuid primary key references auth.users on delete cascade,display_name text not null default '',avatar_path text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.places(id uuid primary key default gen_random_uuid(),google_place_id text,name text not null check(length(name) between 1 and 200),address text,latitude double precision check(latitude between -90 and 90),longitude double precision check(longitude between -180 and 180),google_maps_url text,category text,created_by uuid not null references auth.users on delete cascade,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create index places_google_id_idx on public.places(created_by,google_place_id) where google_place_id is not null;
create table public.visits(id uuid primary key default gen_random_uuid(),place_id uuid not null references public.places on delete cascade,user_id uuid not null references auth.users on delete cascade,visited_at date not null default current_date,rating int check(rating between 1 and 5),comment text not null default '' check(length(comment)<=10000),visibility public.visit_visibility not null default 'private',is_favorite boolean not null default false,is_wishlist boolean not null default false,category text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create index visits_user_date_idx on public.visits(user_id,visited_at desc);
create table public.photos(id uuid primary key default gen_random_uuid(),visit_id uuid not null references public.visits on delete cascade,user_id uuid not null references auth.users on delete cascade,storage_path text not null unique,thumbnail_path text,sort_order int not null default 0,width int,height int,file_size int check(file_size<=15728640),mime_type text check(mime_type in ('image/jpeg','image/webp')),created_at timestamptz not null default now());
create table public.tags(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users on delete cascade,name text not null check(length(name) between 1 and 50),created_at timestamptz not null default now(),unique(user_id,name));
create table public.visit_tags(visit_id uuid references public.visits on delete cascade,tag_id uuid references public.tags on delete cascade,primary key(visit_id,tag_id));
create table public.groups(id uuid primary key default gen_random_uuid(),name text not null check(length(name) between 1 and 100),owner_id uuid not null references auth.users on delete cascade,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.group_members(group_id uuid references public.groups on delete cascade,user_id uuid references auth.users on delete cascade,role public.group_role not null default 'viewer',joined_at timestamptz not null default now(),primary key(group_id,user_id));
create table public.visit_groups(visit_id uuid references public.visits on delete cascade,group_id uuid references public.groups on delete cascade,primary key(visit_id,group_id));
create table public.group_invites(id uuid primary key default gen_random_uuid(),group_id uuid not null references public.groups on delete cascade,token_hash text not null unique,role public.group_role not null check(role<>'owner'),expires_at timestamptz not null,max_uses int not null default 1 check(max_uses between 1 and 100),used_count int not null default 0,revoked_at timestamptz,created_by uuid not null references auth.users,created_at timestamptz not null default now());
create table public.share_links(id uuid primary key default gen_random_uuid(),visit_id uuid not null references public.visits on delete cascade,token_hash text not null unique,expires_at timestamptz,revoked_at timestamptz,created_by uuid not null references auth.users,created_at timestamptz not null default now());
create or replace function public.touch_updated_at() returns trigger language plpgsql set search_path='' as $$begin new.updated_at=now();return new;end$$;
create trigger profiles_touch before update on public.profiles for each row execute function public.touch_updated_at(); create trigger places_touch before update on public.places for each row execute function public.touch_updated_at(); create trigger visits_touch before update on public.visits for each row execute function public.touch_updated_at(); create trigger groups_touch before update on public.groups for each row execute function public.touch_updated_at();
create or replace function public.new_user_profile() returns trigger language plpgsql security definer set search_path='' as $$begin insert into public.profiles(id,display_name) values(new.id,coalesce(new.raw_user_meta_data->>'name',''));return new;end$$;
create trigger auth_user_created after insert on auth.users for each row execute function public.new_user_profile();
create or replace function public.is_group_member(gid uuid,roles public.group_role[] default null) returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.group_members m where m.group_id=gid and m.user_id=auth.uid() and (roles is null or m.role=any(roles)))$$;
create or replace function public.can_view_visit(vid uuid) returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.visits v where v.id=vid and (v.user_id=auth.uid() or (v.visibility='group' and exists(select 1 from public.visit_groups vg join public.group_members gm on gm.group_id=vg.group_id where vg.visit_id=v.id and gm.user_id=auth.uid()))))$$;
create or replace function public.can_edit_visit(vid uuid) returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.visits v where v.id=vid and (v.user_id=auth.uid() or (v.visibility='group' and exists(select 1 from public.visit_groups vg join public.group_members gm on gm.group_id=vg.group_id where vg.visit_id=v.id and gm.user_id=auth.uid() and gm.role in ('owner','editor')))))$$;
create or replace function public.add_group_owner() returns trigger language plpgsql security definer set search_path='' as $$begin insert into public.group_members(group_id,user_id,role) values(new.id,new.owner_id,'owner');return new;end$$;
create trigger group_owner after insert on public.groups for each row execute function public.add_group_owner();
alter table public.profiles enable row level security;alter table public.places enable row level security;alter table public.visits enable row level security;alter table public.photos enable row level security;alter table public.tags enable row level security;alter table public.visit_tags enable row level security;alter table public.groups enable row level security;alter table public.group_members enable row level security;alter table public.visit_groups enable row level security;alter table public.group_invites enable row level security;alter table public.share_links enable row level security;
create policy profiles_self_read on public.profiles for select using(id=auth.uid());create policy profiles_group_read on public.profiles for select using(exists(select 1 from public.group_members mine join public.group_members theirs on mine.group_id=theirs.group_id where mine.user_id=auth.uid() and theirs.user_id=profiles.id));create policy profiles_self_update on public.profiles for update using(id=auth.uid()) with check(id=auth.uid());
create policy places_read on public.places for select using(created_by=auth.uid() or exists(select 1 from public.visits v where v.place_id=places.id and public.can_view_visit(v.id)));create policy places_insert on public.places for insert with check(created_by=auth.uid());create policy places_update on public.places for update using(created_by=auth.uid()) with check(created_by=auth.uid());create policy places_delete on public.places for delete using(created_by=auth.uid());
create policy visits_read on public.visits for select using(public.can_view_visit(id));create policy visits_insert on public.visits for insert with check(user_id=auth.uid());create policy visits_update on public.visits for update using(public.can_edit_visit(id)) with check(user_id=auth.uid() or public.can_edit_visit(id));create policy visits_delete on public.visits for delete using(user_id=auth.uid() or exists(select 1 from public.visit_groups vg where vg.visit_id=id and public.is_group_member(vg.group_id,array['owner']::public.group_role[])));
create policy photos_read on public.photos for select using(public.can_view_visit(visit_id));create policy photos_write on public.photos for insert with check(user_id=auth.uid() and public.can_edit_visit(visit_id));create policy photos_update on public.photos for update using(public.can_edit_visit(visit_id)) with check(user_id=auth.uid());create policy photos_delete on public.photos for delete using(public.can_edit_visit(visit_id));
create policy tags_own on public.tags for all using(user_id=auth.uid()) with check(user_id=auth.uid());create policy visit_tags_read on public.visit_tags for select using(public.can_view_visit(visit_id));create policy visit_tags_write on public.visit_tags for all using(public.can_edit_visit(visit_id)) with check(public.can_edit_visit(visit_id));
create policy groups_read on public.groups for select using(public.is_group_member(id));create policy groups_insert on public.groups for insert with check(owner_id=auth.uid());create policy groups_update on public.groups for update using(owner_id=auth.uid()) with check(owner_id=auth.uid());create policy groups_delete on public.groups for delete using(owner_id=auth.uid());
create policy members_read on public.group_members for select using(public.is_group_member(group_id));create policy members_owner_write on public.group_members for all using(public.is_group_member(group_id,array['owner']::public.group_role[])) with check(public.is_group_member(group_id,array['owner']::public.group_role[]));create policy visit_groups_read on public.visit_groups for select using(public.can_view_visit(visit_id));create policy visit_groups_write on public.visit_groups for all using(public.can_edit_visit(visit_id)) with check(public.can_edit_visit(visit_id) and public.is_group_member(group_id,array['owner','editor']::public.group_role[]));
create policy invites_owner on public.group_invites for all using(public.is_group_member(group_id,array['owner']::public.group_role[])) with check(created_by=auth.uid() and public.is_group_member(group_id,array['owner']::public.group_role[]));create policy links_owner on public.share_links for all using(created_by=auth.uid()) with check(created_by=auth.uid() and public.can_edit_visit(visit_id));
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('visit-photos','visit-photos',false,15728640,array['image/jpeg','image/webp']),('avatars','avatars',false,5242880,array['image/jpeg','image/webp']) on conflict(id) do nothing;
create policy visit_photo_objects_read on storage.objects for select using(bucket_id='visit-photos' and public.can_view_visit((storage.foldername(name))[2]::uuid));create policy visit_photo_objects_insert on storage.objects for insert with check(bucket_id='visit-photos' and (storage.foldername(name))[1]=auth.uid()::text and public.can_edit_visit((storage.foldername(name))[2]::uuid));create policy visit_photo_objects_delete on storage.objects for delete using(bucket_id='visit-photos' and public.can_edit_visit((storage.foldername(name))[2]::uuid));create policy avatars_own on storage.objects for all using(bucket_id='avatars' and (storage.foldername(name))[1]=auth.uid()::text) with check(bucket_id='avatars' and (storage.foldername(name))[1]=auth.uid()::text);
commit;
